def draw_box():
    for i in range(14):
        if i == 0 or i == 13:
            print('*' * 10)
        else:
            print('*', ' ' * 6, '*')

# основная программа
draw_box()

# объявление функции
def draw_triangle():
    for i in range(1, 11):
        print('*' * i)

# основная программа
draw_triangle()  # вызов функции

# объявление функции
def get_days(month):
    if month == 2:
        res = 28
    elif month == 4 or month == 6 or month == 9 or month == 11:
        res = 30
    else:
        res = 31
    return res
# считываем данные
num = int(input())

# вызываем функцию
print(get_days(num))
